const episodes = $('Query Season 3 Episodes').all();
const tasks = $('Query Critical Open Tasks').all();

// Group episodes by status
const byStatus = {};
episodes.forEach(ep => {
  const props = ep.json.properties;
  const status = props['Status']?.select?.name || 'Unknown';
  const label = props['Episode #']?.title?.[0]?.plain_text || '?';
  const uploadStatus = props['Upload Status']?.select?.name || '—';
  if (!byStatus[status]) byStatus[status] = [];
  byStatus[status].push(`${label} (Upload: ${uploadStatus})`);
});

const statusOrder = ['Planning', 'Pre-Production', 'In Production', 'Post-Production', 'Aired', 'Archived'];
const lines = [];
lines.push('═══ GSR WEEKLY PIPELINE REPORT ═══');
lines.push(`Week of: ${new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}`);
lines.push('');

statusOrder.forEach(s => {
  if (byStatus[s]) {
    lines.push(`${s.toUpperCase()} (${byStatus[s].length})`);
    byStatus[s].forEach(ep => lines.push(`  • ${ep}`));
    lines.push('');
  }
});

if (tasks.length > 0) {
  lines.push(`CRITICAL OPEN TASKS (${tasks.length})`);
  tasks.forEach(t => {
    const name = t.json.properties['Name']?.title?.[0]?.plain_text || '?';
    lines.push(`  ⚠ ${name}`);
  });
}

const total = episodes.length;
const aired = (byStatus['Aired'] || []).length;
const pct = Math.round(aired / total * 100);
lines.push('');
lines.push(`Season Progress: ${aired}/${total} episodes aired (${pct}%)`);

return [{ json: { report: lines.join('\n'), airedCount: aired, total, criticalTasks: tasks.length } }];
